BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Buerger''s Disease' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Buerger''s Disease', 'TAO diagnosis, tobacco cessation, and management', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Buerger''s Disease (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Buerger''s Disease - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Core definition in this vascular case?', 'Which finding best supports Core definition in this vascular case?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "Buerger''s disease (thromboangiitis obliterans) is an inflammatory occlusive disease of small and medium arteries and veins."}, {"id": "c", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "d", "text": "Only coronary vessels are affected in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Buerger''s disease (thromboangiitis obliterans) is an inflammatory occlusive disease of small and medium arteries and veins. Differentiate inflammatory tobacco-related occlusion from atherosclerotic PAD early.', 'Buerger''s Disease - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches Pathologic process?', 'The nurse reviews assessment data. Which interpretation best matches Pathologic process?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Monitor for progressive ischemia as occlusion advances segmentally."}, {"id": "c", "text": "This profile is more consistent with Typical patient profile."}, {"id": "d", "text": "Diffuse valve incompetence is primary lesion in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Disease causes segmental thrombosis and fibrosis in extremity vessels. Monitor for progressive ischemia as occlusion advances segmentally.', 'Buerger''s Disease - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Tobacco exclusivity?', 'Which clinical judgment is most accurate regarding Tobacco exclusivity?', '[{"id": "a", "text": "Only alcohol causes this disease in this note."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "Buerger disease is almost exclusively caused by tobacco exposure, including cigarettes and smokeless products."}, {"id": "d", "text": "This profile is more consistent with Distribution pattern."}]'::jsonb, '["c"]'::jsonb, 'Correct because Buerger disease is almost exclusively caused by tobacco exposure, including cigarettes and smokeless products. Absolute cessation of all tobacco/nicotine exposure is mandatory.', 'Buerger''s Disease - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Not atherosclerosis?', 'In urgent prioritization, which conclusion aligns with Not atherosclerosis?', '[{"id": "a", "text": "Avoid conflating TAO with classic PAD risk modeling."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "This profile is more consistent with BURGER mnemonic - burning pain."}, {"id": "d", "text": "TAO is identical to PAD plaque disease in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Buerger''s is not atherosclerosis; it is an inflammatory immune-mediated process. Avoid conflating TAO with classic PAD risk modeling.', 'Buerger''s Disease - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Typical patient profile?', 'Which statement most appropriately reflects Typical patient profile?', '[{"id": "a", "text": "This profile is more consistent with BURGER mnemonic - ulcers."}, {"id": "b", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "c", "text": "Gender/age profile is irrelevant in this note."}, {"id": "d", "text": "Typical profile is heavy tobacco user, often young male under 45; women less common but rising with tobacco use."}]'::jsonb, '["d"]'::jsonb, 'Correct because Typical profile is heavy tobacco user, often young male under 45; women less common but rising with tobacco use. Suspect TAO in young smokers with bilateral ischemic extremity signs.', 'Buerger''s Disease - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Distribution pattern in this vascular case?', 'Which finding best supports Distribution pattern in this vascular case?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Upper-limb ischemia in smoker should raise TAO suspicion."}, {"id": "c", "text": "TAO affects only lower limbs in this note."}, {"id": "d", "text": "Pulse and color trends are not relevant to TAO progression."}]'::jsonb, '["b"]'::jsonb, 'Correct because Buerger disease may involve both upper and lower extremities, unlike PAD that mainly affects lower limbs. Upper-limb ischemia in smoker should raise TAO suspicion.', 'Buerger''s Disease - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches BURGER mnemonic - burning pain?', 'The nurse reviews assessment data. Which interpretation best matches BURGER mnemonic - burning pain?', '[{"id": "a", "text": "Pain appears only with exertion and never at rest in this note."}, {"id": "b", "text": "Burning ischemic pain at rest in fingers/toes/feet is a key symptom."}, {"id": "c", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "d", "text": "Pulse and color trends are not relevant to TAO progression."}]'::jsonb, '["b"]'::jsonb, 'Correct because Burning ischemic pain at rest in fingers/toes/feet is a key symptom. Rest pain indicates significant ischemia requiring urgent management.', 'Buerger''s Disease - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding BURGER mnemonic - ulcers?', 'Which clinical judgment is most accurate regarding BURGER mnemonic - ulcers?', '[{"id": "a", "text": "This profile is more consistent with BURGER mnemonic - extremity coolness."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "Protect ulcerated ischemic tissue and prevent infection progression."}, {"id": "d", "text": "Cessation counseling can be deferred until after tissue loss occurs."}]'::jsonb, '["c"]'::jsonb, 'Correct because Painful ulceration of fingertips/toes is listed in BURGER mnemonic. Protect ulcerated ischemic tissue and prevent infection progression.', 'Buerger''s Disease - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with BURGER mnemonic - rubor?', 'In urgent prioritization, which conclusion aligns with BURGER mnemonic - rubor?', '[{"id": "a", "text": "This profile is more consistent with BURGER mnemonic - reduced pulses."}, {"id": "b", "text": "Dependent rubor/redness and Raynaud-like color changes are characteristic findings."}, {"id": "c", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "d", "text": "Cessation counseling can be deferred until after tissue loss occurs."}]'::jsonb, '["b"]'::jsonb, 'Correct because Dependent rubor/redness and Raynaud-like color changes are characteristic findings. Interpret positional color shifts as ischemic vascular dysfunction.', 'Buerger''s Disease - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects BURGER mnemonic - gangrene?', 'Which statement most appropriately reflects BURGER mnemonic - gangrene?', '[{"id": "a", "text": "Gangrene is never seen in TAO in this note."}, {"id": "b", "text": "This profile is more consistent with Additional signs."}, {"id": "c", "text": "Escalate when tissue viability declines toward amputation risk."}, {"id": "d", "text": "Only wet gangrene is described in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Dry gangrene of digits may occur in advanced disease. Escalate when tissue viability declines toward amputation risk.', 'Buerger''s Disease - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports BURGER mnemonic - extremity coolness in this vascular case?', 'Which finding best supports BURGER mnemonic - extremity coolness in this vascular case?', '[{"id": "a", "text": "Extremities are often cool to touch, especially hands and feet."}, {"id": "b", "text": "This profile is more consistent with Allen test purpose."}, {"id": "c", "text": "Extremities are warm and flushed in TAO in this note."}, {"id": "d", "text": "Temperature is unrelated to TAO in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Extremities are often cool to touch, especially hands and feet. Frequent perfusion checks are needed in cool ischemic limbs.', 'Buerger''s Disease - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches BURGER mnemonic - reduced pulses?', 'The nurse reviews assessment data. Which interpretation best matches BURGER mnemonic - reduced pulses?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Pulses remain strong in severe TAO in this note."}, {"id": "c", "text": "This profile is more consistent with Allen test steps."}, {"id": "d", "text": "Track pulse changes serially to detect worsening ischemia."}]'::jsonb, '["d"]'::jsonb, 'Correct because Distal pulses (pedal/radial) are reduced or absent. Track pulse changes serially to detect worsening ischemia.', 'Buerger''s Disease - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Additional signs?', 'Which clinical judgment is most accurate regarding Additional signs?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Neurologic changes are excluded in this note."}, {"id": "c", "text": "Only cardiac murmurs diagnose TAO in this note."}, {"id": "d", "text": "Additional signs include migratory superficial thrombophlebitis, intermittent claudication, nail changes, and ischemic neuropathy."}]'::jsonb, '["d"]'::jsonb, 'Correct because Additional signs include migratory superficial thrombophlebitis, intermittent claudication, nail changes, and ischemic neuropathy. Recognize multisystem limb signs beyond pain alone.', 'Buerger''s Disease - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Allen test purpose?', 'In urgent prioritization, which conclusion aligns with Allen test purpose?', '[{"id": "a", "text": "Use Allen test correctly before arterial procedures and in TAO evaluation."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "This profile is more consistent with Angiography hallmark."}, {"id": "d", "text": "Allen test is unrelated to arterial patency in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Allen test assesses radial/ulnar patency and upper-extremity circulation. Use Allen test correctly before arterial procedures and in TAO evaluation.', 'Buerger''s Disease - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Allen test steps?', 'Which statement most appropriately reflects Allen test steps?', '[{"id": "a", "text": "This profile is more consistent with Other diagnostics."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "Steps include fist clench, compress both radial/ulnar arteries, open blanched hand, release one artery, and observe reperfusion."}, {"id": "d", "text": "Cessation counseling can be deferred until after tissue loss occurs."}]'::jsonb, '["c"]'::jsonb, 'Correct because Steps include fist clench, compress both radial/ulnar arteries, open blanched hand, release one artery, and observe reperfusion. Sequence accuracy is crucial for valid test interpretation.', 'Buerger''s Disease - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Allen test interpretation in this vascular case?', 'Which finding best supports Allen test interpretation in this vascular case?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Delayed reperfusion indicates compromised arterial patency."}, {"id": "c", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "d", "text": "Persistent pallor confirms normal flow in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Normal test is flush within 5–7 seconds after release; persistent pallor suggests occlusion. Delayed reperfusion indicates compromised arterial patency.', 'Buerger''s Disease - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches Angiography hallmark?', 'The nurse reviews assessment data. Which interpretation best matches Angiography hallmark?', '[{"id": "a", "text": "This profile is more consistent with Nicotine product caution."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "d", "text": "Angiography finding of corkscrew collaterals is pathognomonic for Buerger disease."}]'::jsonb, '["d"]'::jsonb, 'Correct because Angiography finding of corkscrew collaterals is pathognomonic for Buerger disease. Use angiographic pattern to strengthen diagnosis when clinical picture fits.', 'Buerger''s Disease - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Other diagnostics?', 'Which clinical judgment is most accurate regarding Other diagnostics?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "Diagnosis is clinical plus imaging after excluding mimics."}, {"id": "c", "text": "Single specific blood biomarker confirms TAO in this note."}, {"id": "d", "text": "Cessation counseling can be deferred until after tissue loss occurs."}]'::jsonb, '["b"]'::jsonb, 'Correct because Doppler and ABI may be used; blood tests are used to rule out autoimmune/hypercoagulable causes, with no reliable biomarker. Diagnosis is clinical plus imaging after excluding mimics.', 'Buerger''s Disease - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Primary treatment?', 'In urgent prioritization, which conclusion aligns with Primary treatment?', '[{"id": "a", "text": "This profile is more consistent with Amputation context."}, {"id": "b", "text": "Revascularization alone halts TAO despite smoking in this note."}, {"id": "c", "text": "Absolute cessation of all smoking/tobacco is the only intervention that halts progression."}, {"id": "d", "text": "Pulse and color trends are not relevant to TAO progression."}]'::jsonb, '["c"]'::jsonb, 'Correct because Absolute cessation of all smoking/tobacco is the only intervention that halts progression. Prioritize cessation counseling as non-negotiable first intervention.', 'Buerger''s Disease - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Nicotine product caution?', 'Which statement most appropriately reflects Nicotine product caution?', '[{"id": "a", "text": "Teach that nicotine itself may perpetuate TAO process."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "Nicotine patches are guaranteed curative in TAO in this note."}, {"id": "d", "text": "Cessation counseling can be deferred until after tissue loss occurs."}]'::jsonb, '["a"]'::jsonb, 'Correct because Nicotine patches/gums may worsen disease because nicotine exposure can maintain activity. Teach that nicotine itself may perpetuate TAO process.', 'Buerger''s Disease - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Supportive therapy in this vascular case?', 'Which finding best supports Supportive therapy in this vascular case?', '[{"id": "a", "text": "Cold exposure is recommended in this note."}, {"id": "b", "text": "Supportive management includes wound care, CCB for vasospasm, iloprost for severe ischemia, pain control, and avoiding cold."}, {"id": "c", "text": "Supportive care is unnecessary if ulcers present in this note."}, {"id": "d", "text": "This profile is more consistent with Buerger vs PAD vessel/risk patterns."}]'::jsonb, '["b"]'::jsonb, 'Correct because Supportive management includes wound care, CCB for vasospasm, iloprost for severe ischemia, pain control, and avoiding cold. Adjunctive care supports tissue survival but does not replace cessation.', 'Buerger''s Disease - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches Amputation context?', 'The nurse reviews assessment data. Which interpretation best matches Amputation context?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Monitor tissue viability closely to time surgical escalation appropriately."}, {"id": "c", "text": "Amputation is contraindicated in all cases in this note."}, {"id": "d", "text": "This profile is more consistent with NCLEX priority synthesis."}]'::jsonb, '["b"]'::jsonb, 'Correct because Amputation may be required when gangrene is non-viable. Monitor tissue viability closely to time surgical escalation appropriately.', 'Buerger''s Disease - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Buerger vs PAD cause/age?', 'Which clinical judgment is most accurate regarding Buerger vs PAD cause/age?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Buerger is tobacco-induced in younger patients (<45), while PAD is atherosclerotic and generally older (>50)."}, {"id": "c", "text": "Buerger is primarily elderly disease in this note."}, {"id": "d", "text": "Pulse and color trends are not relevant to TAO progression."}]'::jsonb, '["b"]'::jsonb, 'Correct because Buerger is tobacco-induced in younger patients (<45), while PAD is atherosclerotic and generally older (>50). Age-plus-risk profile helps rapid differential diagnosis.', 'Buerger''s Disease - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Buerger vs PAD vessel/risk patterns?', 'In urgent prioritization, which conclusion aligns with Buerger vs PAD vessel/risk patterns?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "c", "text": "Distribution and risk-factor pattern guide triage and counseling focus."}, {"id": "d", "text": "Buerger affects only large proximal vessels in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Buerger affects small/medium vessels in upper and lower limbs with tobacco-only risk; PAD affects large/medium mostly lower limbs with multiple metabolic risks. Distribution and risk-factor pattern guide triage and counseling focus.', 'Buerger''s Disease - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects NCLEX priority synthesis?', 'Which statement most appropriately reflects NCLEX priority synthesis?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "Gangrene monitoring is low priority in this note."}, {"id": "c", "text": "NCLEX priority: young male smoker with bilateral ischemia suggests Buerger; immediate STOP ALL TOBACCO and monitor gangrene progression."}, {"id": "d", "text": "This profile is more consistent with Tobacco exclusivity."}]'::jsonb, '["c"]'::jsonb, 'Correct because NCLEX priority: young male smoker with bilateral ischemia suggests Buerger; immediate STOP ALL TOBACCO and monitor gangrene progression. Frame all teaching around mandatory cessation and limb preservation.', 'Buerger''s Disease - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Core definition in this vascular case?', 'Which finding best supports Core definition in this vascular case?', '[{"id": "a", "text": "Differentiate inflammatory tobacco-related occlusion from atherosclerotic PAD early."}, {"id": "b", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "c", "text": "This profile is more consistent with Not atherosclerosis."}, {"id": "d", "text": "Buerger disease is primary large-vessel atherosclerosis in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Buerger''s disease (thromboangiitis obliterans) is an inflammatory occlusive disease of small and medium arteries and veins. Differentiate inflammatory tobacco-related occlusion from atherosclerotic PAD early.', 'Buerger''s Disease - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches Pathologic process?', 'The nurse reviews assessment data. Which interpretation best matches Pathologic process?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Diffuse valve incompetence is primary lesion in this note."}, {"id": "c", "text": "Disease causes segmental thrombosis and fibrosis in extremity vessels."}, {"id": "d", "text": "No thrombosis occurs in this disease in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Disease causes segmental thrombosis and fibrosis in extremity vessels. Monitor for progressive ischemia as occlusion advances segmentally.', 'Buerger''s Disease - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Tobacco exclusivity?', 'Which clinical judgment is most accurate regarding Tobacco exclusivity?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "Absolute cessation of all tobacco/nicotine exposure is mandatory."}, {"id": "d", "text": "Disease is unrelated to tobacco in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Buerger disease is almost exclusively caused by tobacco exposure, including cigarettes and smokeless products. Absolute cessation of all tobacco/nicotine exposure is mandatory.', 'Buerger''s Disease - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Not atherosclerosis?', 'In urgent prioritization, which conclusion aligns with Not atherosclerosis?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Buerger''s is not atherosclerosis; it is an inflammatory immune-mediated process."}, {"id": "c", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "d", "text": "This profile is more consistent with BURGER mnemonic - burning pain."}]'::jsonb, '["b"]'::jsonb, 'Correct because Buerger''s is not atherosclerosis; it is an inflammatory immune-mediated process. Avoid conflating TAO with classic PAD risk modeling.', 'Buerger''s Disease - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Typical patient profile?', 'Which statement most appropriately reflects Typical patient profile?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "TAO is primarily disease of nonsmoking elderly in this note."}, {"id": "c", "text": "This profile is more consistent with BURGER mnemonic - ulcers."}, {"id": "d", "text": "Suspect TAO in young smokers with bilateral ischemic extremity signs."}]'::jsonb, '["d"]'::jsonb, 'Correct because Typical profile is heavy tobacco user, often young male under 45; women less common but rising with tobacco use. Suspect TAO in young smokers with bilateral ischemic extremity signs.', 'Buerger''s Disease - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Distribution pattern in this vascular case?', 'Which finding best supports Distribution pattern in this vascular case?', '[{"id": "a", "text": "Buerger disease may involve both upper and lower extremities, unlike PAD that mainly affects lower limbs."}, {"id": "b", "text": "TAO affects only lower limbs in this note."}, {"id": "c", "text": "PAD primarily affects upper limbs in this note."}, {"id": "d", "text": "This profile is more consistent with BURGER mnemonic - rubor."}]'::jsonb, '["a"]'::jsonb, 'Correct because Buerger disease may involve both upper and lower extremities, unlike PAD that mainly affects lower limbs. Upper-limb ischemia in smoker should raise TAO suspicion.', 'Buerger''s Disease - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches BURGER mnemonic - burning pain?', 'The nurse reviews assessment data. Which interpretation best matches BURGER mnemonic - burning pain?', '[{"id": "a", "text": "Pain appears only with exertion and never at rest in this note."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "This profile is more consistent with BURGER mnemonic - gangrene."}, {"id": "d", "text": "Rest pain indicates significant ischemia requiring urgent management."}]'::jsonb, '["d"]'::jsonb, 'Correct because Burning ischemic pain at rest in fingers/toes/feet is a key symptom. Rest pain indicates significant ischemia requiring urgent management.', 'Buerger''s Disease - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding BURGER mnemonic - ulcers?', 'Which clinical judgment is most accurate regarding BURGER mnemonic - ulcers?', '[{"id": "a", "text": "Painful ulceration of fingertips/toes is listed in BURGER mnemonic."}, {"id": "b", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "c", "text": "Ulceration never occurs in TAO in this note."}, {"id": "d", "text": "This profile is more consistent with BURGER mnemonic - extremity coolness."}]'::jsonb, '["a"]'::jsonb, 'Correct because Painful ulceration of fingertips/toes is listed in BURGER mnemonic. Protect ulcerated ischemic tissue and prevent infection progression.', 'Buerger''s Disease - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with BURGER mnemonic - rubor?', 'In urgent prioritization, which conclusion aligns with BURGER mnemonic - rubor?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "Color is unaffected by position in this note."}, {"id": "c", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "d", "text": "Interpret positional color shifts as ischemic vascular dysfunction."}]'::jsonb, '["d"]'::jsonb, 'Correct because Dependent rubor/redness and Raynaud-like color changes are characteristic findings. Interpret positional color shifts as ischemic vascular dysfunction.', 'Buerger''s Disease - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects BURGER mnemonic - gangrene?', 'Which statement most appropriately reflects BURGER mnemonic - gangrene?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "This profile is more consistent with Additional signs."}, {"id": "c", "text": "Dry gangrene of digits may occur in advanced disease."}, {"id": "d", "text": "Gangrene is never seen in TAO in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Dry gangrene of digits may occur in advanced disease. Escalate when tissue viability declines toward amputation risk.', 'Buerger''s Disease - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports BURGER mnemonic - extremity coolness in this vascular case?', 'Which finding best supports BURGER mnemonic - extremity coolness in this vascular case?', '[{"id": "a", "text": "Temperature is unrelated to TAO in this note."}, {"id": "b", "text": "Extremities are warm and flushed in TAO in this note."}, {"id": "c", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "d", "text": "Frequent perfusion checks are needed in cool ischemic limbs."}]'::jsonb, '["d"]'::jsonb, 'Correct because Extremities are often cool to touch, especially hands and feet. Frequent perfusion checks are needed in cool ischemic limbs.', 'Buerger''s Disease - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches BURGER mnemonic - reduced pulses?', 'The nurse reviews assessment data. Which interpretation best matches BURGER mnemonic - reduced pulses?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "Distal pulses (pedal/radial) are reduced or absent."}, {"id": "c", "text": "Pulse checks are unnecessary in TAO in this note."}, {"id": "d", "text": "This profile is more consistent with Allen test steps."}]'::jsonb, '["b"]'::jsonb, 'Correct because Distal pulses (pedal/radial) are reduced or absent. Track pulse changes serially to detect worsening ischemia.', 'Buerger''s Disease - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Additional signs?', 'Which clinical judgment is most accurate regarding Additional signs?', '[{"id": "a", "text": "This profile is more consistent with Allen test interpretation."}, {"id": "b", "text": "Only cardiac murmurs diagnose TAO in this note."}, {"id": "c", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "d", "text": "Recognize multisystem limb signs beyond pain alone."}]'::jsonb, '["d"]'::jsonb, 'Correct because Additional signs include migratory superficial thrombophlebitis, intermittent claudication, nail changes, and ischemic neuropathy. Recognize multisystem limb signs beyond pain alone.', 'Buerger''s Disease - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Allen test purpose?', 'In urgent prioritization, which conclusion aligns with Allen test purpose?', '[{"id": "a", "text": "Allen test assesses radial/ulnar patency and upper-extremity circulation."}, {"id": "b", "text": "This profile is more consistent with Angiography hallmark."}, {"id": "c", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "d", "text": "Allen test is unrelated to arterial patency in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Allen test assesses radial/ulnar patency and upper-extremity circulation. Use Allen test correctly before arterial procedures and in TAO evaluation.', 'Buerger''s Disease - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Allen test steps?', 'Which statement most appropriately reflects Allen test steps?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "c", "text": "Sequence accuracy is crucial for valid test interpretation."}, {"id": "d", "text": "This profile is more consistent with Other diagnostics."}]'::jsonb, '["c"]'::jsonb, 'Correct because Steps include fist clench, compress both radial/ulnar arteries, open blanched hand, release one artery, and observe reperfusion. Sequence accuracy is crucial for valid test interpretation.', 'Buerger''s Disease - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Allen test interpretation in this vascular case?', 'Which finding best supports Allen test interpretation in this vascular case?', '[{"id": "a", "text": "Normal test is flush within 5–7 seconds after release; persistent pallor suggests occlusion."}, {"id": "b", "text": "This profile is more consistent with Primary treatment."}, {"id": "c", "text": "Any refill after 30 seconds is still normal in this note."}, {"id": "d", "text": "Cessation counseling can be deferred until after tissue loss occurs."}]'::jsonb, '["a"]'::jsonb, 'Correct because Normal test is flush within 5–7 seconds after release; persistent pallor suggests occlusion. Delayed reperfusion indicates compromised arterial patency.', 'Buerger''s Disease - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches Angiography hallmark?', 'The nurse reviews assessment data. Which interpretation best matches Angiography hallmark?', '[{"id": "a", "text": "Use angiographic pattern to strengthen diagnosis when clinical picture fits."}, {"id": "b", "text": "Corkscrew pattern indicates PAD only in this note."}, {"id": "c", "text": "This profile is more consistent with Nicotine product caution."}, {"id": "d", "text": "Cessation counseling can be deferred until after tissue loss occurs."}]'::jsonb, '["a"]'::jsonb, 'Correct because Angiography finding of corkscrew collaterals is pathognomonic for Buerger disease. Use angiographic pattern to strengthen diagnosis when clinical picture fits.', 'Buerger''s Disease - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Other diagnostics?', 'Which clinical judgment is most accurate regarding Other diagnostics?', '[{"id": "a", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "b", "text": "Doppler and ABI may be used; blood tests are used to rule out autoimmune/hypercoagulable causes, with no reliable biomarker."}, {"id": "c", "text": "No imaging is required for diagnosis in this note."}, {"id": "d", "text": "Cessation counseling can be deferred until after tissue loss occurs."}]'::jsonb, '["b"]'::jsonb, 'Correct because Doppler and ABI may be used; blood tests are used to rule out autoimmune/hypercoagulable causes, with no reliable biomarker. Diagnosis is clinical plus imaging after excluding mimics.', 'Buerger''s Disease - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Primary treatment?', 'In urgent prioritization, which conclusion aligns with Primary treatment?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "This profile is more consistent with Amputation context."}, {"id": "c", "text": "Revascularization alone halts TAO despite smoking in this note."}, {"id": "d", "text": "Prioritize cessation counseling as non-negotiable first intervention."}]'::jsonb, '["d"]'::jsonb, 'Correct because Absolute cessation of all smoking/tobacco is the only intervention that halts progression. Prioritize cessation counseling as non-negotiable first intervention.', 'Buerger''s Disease - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Nicotine product caution?', 'Which statement most appropriately reflects Nicotine product caution?', '[{"id": "a", "text": "Nicotine patches/gums may worsen disease because nicotine exposure can maintain activity."}, {"id": "b", "text": "This profile is more consistent with Buerger vs PAD cause/age."}, {"id": "c", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "d", "text": "Only cigarette smoke, not nicotine, matters in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Nicotine patches/gums may worsen disease because nicotine exposure can maintain activity. Teach that nicotine itself may perpetuate TAO process.', 'Buerger''s Disease - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Supportive therapy in this vascular case?', 'Which finding best supports Supportive therapy in this vascular case?', '[{"id": "a", "text": "Cold exposure is recommended in this note."}, {"id": "b", "text": "Supportive care is unnecessary if ulcers present in this note."}, {"id": "c", "text": "This profile is more consistent with Buerger vs PAD vessel/risk patterns."}, {"id": "d", "text": "Adjunctive care supports tissue survival but does not replace cessation."}]'::jsonb, '["d"]'::jsonb, 'Correct because Supportive management includes wound care, CCB for vasospasm, iloprost for severe ischemia, pain control, and avoiding cold. Adjunctive care supports tissue survival but does not replace cessation.', 'Buerger''s Disease - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews assessment data. Which interpretation best matches Amputation context?', 'The nurse reviews assessment data. Which interpretation best matches Amputation context?', '[{"id": "a", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "b", "text": "Gangrene always reverses without intervention in this note."}, {"id": "c", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "d", "text": "Amputation may be required when gangrene is non-viable."}]'::jsonb, '["d"]'::jsonb, 'Correct because Amputation may be required when gangrene is non-viable. Monitor tissue viability closely to time surgical escalation appropriately.', 'Buerger''s Disease - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Buerger vs PAD cause/age?', 'Which clinical judgment is most accurate regarding Buerger vs PAD cause/age?', '[{"id": "a", "text": "Buerger is primarily elderly disease in this note."}, {"id": "b", "text": "This profile is more consistent with Core definition."}, {"id": "c", "text": "Buerger and PAD share identical etiology in this note."}, {"id": "d", "text": "Age-plus-risk profile helps rapid differential diagnosis."}]'::jsonb, '["d"]'::jsonb, 'Correct because Buerger is tobacco-induced in younger patients (<45), while PAD is atherosclerotic and generally older (>50). Age-plus-risk profile helps rapid differential diagnosis.', 'Buerger''s Disease - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Buerger vs PAD vessel/risk patterns?', 'In urgent prioritization, which conclusion aligns with Buerger vs PAD vessel/risk patterns?', '[{"id": "a", "text": "PAD risk factor is tobacco only in this note."}, {"id": "b", "text": "Cessation counseling can be deferred until after tissue loss occurs."}, {"id": "c", "text": "This profile is more consistent with Pathologic process."}, {"id": "d", "text": "Buerger affects small/medium vessels in upper and lower limbs with tobacco-only risk; PAD affects large/medium mostly lower limbs with multiple metabolic risks."}]'::jsonb, '["d"]'::jsonb, 'Correct because Buerger affects small/medium vessels in upper and lower limbs with tobacco-only risk; PAD affects large/medium mostly lower limbs with multiple metabolic risks. Distribution and risk-factor pattern guide triage and counseling focus.', 'Buerger''s Disease - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects NCLEX priority synthesis?', 'Which statement most appropriately reflects NCLEX priority synthesis?', '[{"id": "a", "text": "Frame all teaching around mandatory cessation and limb preservation."}, {"id": "b", "text": "Pulse and color trends are not relevant to TAO progression."}, {"id": "c", "text": "Smoking cessation is optional in TAO in this note."}, {"id": "d", "text": "Cessation counseling can be deferred until after tissue loss occurs."}]'::jsonb, '["a"]'::jsonb, 'Correct because NCLEX priority: young male smoker with bilateral ischemia suggests Buerger; immediate STOP ALL TOBACCO and monitor gangrene progression. Frame all teaching around mandatory cessation and limb preservation.', 'Buerger''s Disease - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Core definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Core definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Small/medium vessels are involved."}, {"id": "b", "text": "Only coronary vessels are affected in this note."}, {"id": "c", "text": "Both arteries and veins can be affected."}, {"id": "d", "text": "Buerger disease is primary large-vessel atherosclerosis in this note."}, {"id": "e", "text": "TAO is inflammatory and occlusive."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Buerger''s disease (thromboangiitis obliterans) is an inflammatory occlusive disease of small and medium arteries and veins.', 'Buerger''s Disease - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Pathologic process, which statements are correct? (Select all that apply)', 'For management involving Pathologic process, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Extremity vessel involvement is emphasized."}, {"id": "b", "text": "No thrombosis occurs in this disease in this note."}, {"id": "c", "text": "Diffuse valve incompetence is primary lesion in this note."}, {"id": "d", "text": "Segmental thrombosis is described."}, {"id": "e", "text": "Fibrosis of vessels is described."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Disease causes segmental thrombosis and fibrosis in extremity vessels.', 'Buerger''s Disease - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Tobacco exclusivity. Which items should be included? (Select all that apply)', 'The nurse plans care around Tobacco exclusivity. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Tobacco is the near-exclusive trigger."}, {"id": "b", "text": "Only alcohol causes this disease in this note."}, {"id": "c", "text": "Smokeless tobacco is included risk in note."}, {"id": "d", "text": "Continuing tobacco sustains disease activity."}, {"id": "e", "text": "Disease is unrelated to tobacco in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Buerger disease is almost exclusively caused by tobacco exposure, including cigarettes and smokeless products.', 'Buerger''s Disease - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Not atherosclerosis? (Select all that apply)', 'During reassessment, which observations support Not atherosclerosis? (Select all that apply)', '[{"id": "a", "text": "Pathogenesis differs from PAD plaque disease."}, {"id": "b", "text": "Inflammatory/immune mechanisms are emphasized."}, {"id": "c", "text": "TAO is identical to PAD plaque disease in this note."}, {"id": "d", "text": "TAO is non-atherosclerotic in this note."}, {"id": "e", "text": "Immune inflammation is excluded in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Buerger''s is not atherosclerosis; it is an inflammatory immune-mediated process.', 'Buerger''s Disease - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Typical patient profile in this note? (Select all that apply)', 'Which clues are consistent with Typical patient profile in this note? (Select all that apply)', '[{"id": "a", "text": "Female incidence rises with tobacco use."}, {"id": "b", "text": "Gender/age profile is irrelevant in this note."}, {"id": "c", "text": "Young male under 45 is typical profile."}, {"id": "d", "text": "TAO is primarily disease of nonsmoking elderly in this note."}, {"id": "e", "text": "Heavy tobacco use is central risk."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Typical profile is heavy tobacco user, often young male under 45; women less common but rising with tobacco use.', 'Buerger''s Disease - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Distribution pattern. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Distribution pattern. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "PAD is usually lower-extremity predominant in comparison table."}, {"id": "b", "text": "PAD primarily affects upper limbs in this note."}, {"id": "c", "text": "Upper and lower extremities can be affected."}, {"id": "d", "text": "TAO affects only lower limbs in this note."}, {"id": "e", "text": "Distribution helps differential diagnosis."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Buerger disease may involve both upper and lower extremities, unlike PAD that mainly affects lower limbs.', 'Buerger''s Disease - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving BURGER mnemonic - burning pain, which statements are correct? (Select all that apply)', 'For management involving BURGER mnemonic - burning pain, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pain appears only with exertion and never at rest in this note."}, {"id": "b", "text": "Burning pain is in mnemonic."}, {"id": "c", "text": "Pain may occur at rest."}, {"id": "d", "text": "Distal digits/feet are common sites."}, {"id": "e", "text": "Pain is absent in TAO in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Burning ischemic pain at rest in fingers/toes/feet is a key symptom.', 'Buerger''s Disease - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around BURGER mnemonic - ulcers. Which items should be included? (Select all that apply)', 'The nurse plans care around BURGER mnemonic - ulcers. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "TAO ulcers are painless venous stasis ulcers in this note."}, {"id": "b", "text": "Distal ulceration suggests severe ischemia."}, {"id": "c", "text": "Ulcers are painful in TAO profile."}, {"id": "d", "text": "Ulceration never occurs in TAO in this note."}, {"id": "e", "text": "Digit ulcers are highlighted."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Painful ulceration of fingertips/toes is listed in BURGER mnemonic.', 'Buerger''s Disease - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support BURGER mnemonic - rubor? (Select all that apply)', 'During reassessment, which observations support BURGER mnemonic - rubor? (Select all that apply)', '[{"id": "a", "text": "Raynaud-like color changes are listed."}, {"id": "b", "text": "Color is unaffected by position in this note."}, {"id": "c", "text": "Only fixed cyanosis with no variation occurs in this note."}, {"id": "d", "text": "Color changes are part of BURGER mnemonic."}, {"id": "e", "text": "Dependent rubor is listed."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Dependent rubor/redness and Raynaud-like color changes are characteristic findings.', 'Buerger''s Disease - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with BURGER mnemonic - gangrene in this note? (Select all that apply)', 'Which clues are consistent with BURGER mnemonic - gangrene in this note? (Select all that apply)', '[{"id": "a", "text": "Only wet gangrene is described in this note."}, {"id": "b", "text": "Dry gangrene is advanced feature."}, {"id": "c", "text": "Digits are common gangrene location."}, {"id": "d", "text": "Gangrene is never seen in TAO in this note."}, {"id": "e", "text": "Gangrene indicates severe progression."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Dry gangrene of digits may occur in advanced disease.', 'Buerger''s Disease - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for BURGER mnemonic - extremity coolness. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for BURGER mnemonic - extremity coolness. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Cool hands/feet are listed finding."}, {"id": "b", "text": "Distal extremities are emphasized."}, {"id": "c", "text": "Temperature is unrelated to TAO in this note."}, {"id": "d", "text": "Temperature change reflects poor perfusion."}, {"id": "e", "text": "Extremities are warm and flushed in TAO in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Extremities are often cool to touch, especially hands and feet.', 'Buerger''s Disease - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving BURGER mnemonic - reduced pulses, which statements are correct? (Select all that apply)', 'For management involving BURGER mnemonic - reduced pulses, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Reduced or absent pulses are listed."}, {"id": "b", "text": "Pedal/radial pulses specifically mentioned."}, {"id": "c", "text": "Pulse loss indicates arterial compromise."}, {"id": "d", "text": "Pulses remain strong in severe TAO in this note."}, {"id": "e", "text": "Pulse checks are unnecessary in TAO in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Distal pulses (pedal/radial) are reduced or absent.', 'Buerger''s Disease - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Additional signs. Which items should be included? (Select all that apply)', 'The nurse plans care around Additional signs. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Intermittent claudication is listed."}, {"id": "b", "text": "Migratory superficial thrombophlebitis is listed."}, {"id": "c", "text": "Nail/neuropathy changes are listed."}, {"id": "d", "text": "Only cardiac murmurs diagnose TAO in this note."}, {"id": "e", "text": "Neurologic changes are excluded in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Additional signs include migratory superficial thrombophlebitis, intermittent claudication, nail changes, and ischemic neuropathy.', 'Buerger''s Disease - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Allen test purpose? (Select all that apply)', 'During reassessment, which observations support Allen test purpose? (Select all that apply)', '[{"id": "a", "text": "Used for upper-extremity circulation evaluation."}, {"id": "b", "text": "Allen test is unrelated to arterial patency in this note."}, {"id": "c", "text": "Both radial and ulnar arteries are assessed."}, {"id": "d", "text": "Allen test diagnoses DVT in this note."}, {"id": "e", "text": "Allen test evaluates hand arterial flow."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Allen test assesses radial/ulnar patency and upper-extremity circulation.', 'Buerger''s Disease - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Allen test steps in this note? (Select all that apply)', 'Which clues are consistent with Allen test steps in this note? (Select all that apply)', '[{"id": "a", "text": "Release both arteries simultaneously is required in this note."}, {"id": "b", "text": "Both arteries are compressed initially."}, {"id": "c", "text": "Hand should appear pale before release."}, {"id": "d", "text": "Release one artery while keeping the other compressed."}, {"id": "e", "text": "Test begins with leg elevation in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Steps include fist clench, compress both radial/ulnar arteries, open blanched hand, release one artery, and observe reperfusion.', 'Buerger''s Disease - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Allen test interpretation. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Allen test interpretation. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Persistent pallor confirms normal flow in this note."}, {"id": "b", "text": "Flush in 5–7 seconds is normal."}, {"id": "c", "text": "Persistent pallor indicates occlusion."}, {"id": "d", "text": "Any refill after 30 seconds is still normal in this note."}, {"id": "e", "text": "Timing criterion is explicitly provided."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Normal test is flush within 5–7 seconds after release; persistent pallor suggests occlusion.', 'Buerger''s Disease - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Angiography hallmark, which statements are correct? (Select all that apply)', 'For management involving Angiography hallmark, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pattern supports TAO diagnosis."}, {"id": "b", "text": "Corkscrew collaterals are pathognomonic in note."}, {"id": "c", "text": "Angiography is never used in TAO in this note."}, {"id": "d", "text": "Corkscrew pattern indicates PAD only in this note."}, {"id": "e", "text": "Angiography is key diagnostic study."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Angiography finding of corkscrew collaterals is pathognomonic for Buerger disease.', 'Buerger''s Disease - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Other diagnostics. Which items should be included? (Select all that apply)', 'The nurse plans care around Other diagnostics. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "No reliable standalone biomarker is listed."}, {"id": "b", "text": "No imaging is required for diagnosis in this note."}, {"id": "c", "text": "Single specific blood biomarker confirms TAO in this note."}, {"id": "d", "text": "Doppler/ABI are listed supportive studies."}, {"id": "e", "text": "Blood tests help rule out other causes."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Doppler and ABI may be used; blood tests are used to rule out autoimmune/hypercoagulable causes, with no reliable biomarker.', 'Buerger''s Disease - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Primary treatment? (Select all that apply)', 'During reassessment, which observations support Primary treatment? (Select all that apply)', '[{"id": "a", "text": "Smoking cessation is mandatory and first priority."}, {"id": "b", "text": "Smoking reduction without cessation is sufficient in this note."}, {"id": "c", "text": "Progression continues with ongoing tobacco use."}, {"id": "d", "text": "Even low-level smoking can sustain disease activity."}, {"id": "e", "text": "Revascularization alone halts TAO despite smoking in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Absolute cessation of all smoking/tobacco is the only intervention that halts progression.', 'Buerger''s Disease - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Nicotine product caution in this note? (Select all that apply)', 'Which clues are consistent with Nicotine product caution in this note? (Select all that apply)', '[{"id": "a", "text": "Counseling should include smokeless/nicotine products."}, {"id": "b", "text": "Nicotine patches are guaranteed curative in TAO in this note."}, {"id": "c", "text": "Any nicotine exposure is concerning in TAO."}, {"id": "d", "text": "Only cigarette smoke, not nicotine, matters in this note."}, {"id": "e", "text": "Nicotine replacement products may worsen TAO per note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Nicotine patches/gums may worsen disease because nicotine exposure can maintain activity.', 'Buerger''s Disease - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Supportive therapy. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Supportive therapy. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Nifedipine for vasospasm is listed."}, {"id": "b", "text": "Cold exposure is recommended in this note."}, {"id": "c", "text": "Wound care is listed supportive management."}, {"id": "d", "text": "Supportive care is unnecessary if ulcers present in this note."}, {"id": "e", "text": "Avoiding cold triggers is listed advice."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Supportive management includes wound care, CCB for vasospasm, iloprost for severe ischemia, pain control, and avoiding cold.', 'Buerger''s Disease - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Amputation context, which statements are correct? (Select all that apply)', 'For management involving Amputation context, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Gangrene always reverses without intervention in this note."}, {"id": "b", "text": "Advanced ischemia may progress despite support."}, {"id": "c", "text": "Non-viable gangrene can require amputation."}, {"id": "d", "text": "Amputation is contraindicated in all cases in this note."}, {"id": "e", "text": "Gangrene surveillance is key nursing focus."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Amputation may be required when gangrene is non-viable.', 'Buerger''s Disease - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Buerger vs PAD cause/age. Which items should be included? (Select all that apply)', 'The nurse plans care around Buerger vs PAD cause/age. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Buerger cause is tobacco inflammation in table."}, {"id": "b", "text": "Buerger age profile is younger than PAD in table."}, {"id": "c", "text": "Buerger and PAD share identical etiology in this note."}, {"id": "d", "text": "Buerger is primarily elderly disease in this note."}, {"id": "e", "text": "PAD cause is atherosclerosis in table."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Buerger is tobacco-induced in younger patients (<45), while PAD is atherosclerotic and generally older (>50).', 'Buerger''s Disease - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Buerger vs PAD vessel/risk patterns? (Select all that apply)', 'During reassessment, which observations support Buerger vs PAD vessel/risk patterns? (Select all that apply)', '[{"id": "a", "text": "PAD mostly affects lower extremities."}, {"id": "b", "text": "Buerger affects only large proximal vessels in this note."}, {"id": "c", "text": "Buerger can affect upper and lower extremities."}, {"id": "d", "text": "PAD risk factor is tobacco only in this note."}, {"id": "e", "text": "PAD risk list includes HTN/DM/lipids/smoking in table."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Buerger affects small/medium vessels in upper and lower limbs with tobacco-only risk; PAD affects large/medium mostly lower limbs with multiple metabolic risks.', 'Buerger''s Disease - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with NCLEX priority synthesis in this note? (Select all that apply)', 'Which clues are consistent with NCLEX priority synthesis in this note? (Select all that apply)', '[{"id": "a", "text": "Young smoker + bilateral ischemia is key TAO clue."}, {"id": "b", "text": "Gangrene progression monitoring is emphasized."}, {"id": "c", "text": "Stop all tobacco is first intervention."}, {"id": "d", "text": "Smoking cessation is optional in TAO in this note."}, {"id": "e", "text": "Gangrene monitoring is low priority in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: NCLEX priority: young male smoker with bilateral ischemia suggests Buerger; immediate STOP ALL TOBACCO and monitor gangrene progression.', 'Buerger''s Disease - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Core definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Core definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "TAO is inflammatory and occlusive."}, {"id": "b", "text": "Only coronary vessels are affected in this note."}, {"id": "c", "text": "Small/medium vessels are involved."}, {"id": "d", "text": "Buerger disease is primary large-vessel atherosclerosis in this note."}, {"id": "e", "text": "Both arteries and veins can be affected."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Buerger''s disease (thromboangiitis obliterans) is an inflammatory occlusive disease of small and medium arteries and veins.', 'Buerger''s Disease - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Pathologic process, which statements are correct? (Select all that apply)', 'For management involving Pathologic process, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "No thrombosis occurs in this disease in this note."}, {"id": "b", "text": "Extremity vessel involvement is emphasized."}, {"id": "c", "text": "Segmental thrombosis is described."}, {"id": "d", "text": "Fibrosis of vessels is described."}, {"id": "e", "text": "Diffuse valve incompetence is primary lesion in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Disease causes segmental thrombosis and fibrosis in extremity vessels.', 'Buerger''s Disease - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Tobacco exclusivity. Which items should be included? (Select all that apply)', 'The nurse plans care around Tobacco exclusivity. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Disease is unrelated to tobacco in this note."}, {"id": "b", "text": "Continuing tobacco sustains disease activity."}, {"id": "c", "text": "Smokeless tobacco is included risk in note."}, {"id": "d", "text": "Only alcohol causes this disease in this note."}, {"id": "e", "text": "Tobacco is the near-exclusive trigger."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Buerger disease is almost exclusively caused by tobacco exposure, including cigarettes and smokeless products.', 'Buerger''s Disease - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Not atherosclerosis? (Select all that apply)', 'During reassessment, which observations support Not atherosclerosis? (Select all that apply)', '[{"id": "a", "text": "TAO is non-atherosclerotic in this note."}, {"id": "b", "text": "Inflammatory/immune mechanisms are emphasized."}, {"id": "c", "text": "TAO is identical to PAD plaque disease in this note."}, {"id": "d", "text": "Pathogenesis differs from PAD plaque disease."}, {"id": "e", "text": "Immune inflammation is excluded in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Buerger''s is not atherosclerosis; it is an inflammatory immune-mediated process.', 'Buerger''s Disease - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Typical patient profile in this note? (Select all that apply)', 'Which clues are consistent with Typical patient profile in this note? (Select all that apply)', '[{"id": "a", "text": "Female incidence rises with tobacco use."}, {"id": "b", "text": "Gender/age profile is irrelevant in this note."}, {"id": "c", "text": "Young male under 45 is typical profile."}, {"id": "d", "text": "Heavy tobacco use is central risk."}, {"id": "e", "text": "TAO is primarily disease of nonsmoking elderly in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Typical profile is heavy tobacco user, often young male under 45; women less common but rising with tobacco use.', 'Buerger''s Disease - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Distribution pattern. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Distribution pattern. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Distribution helps differential diagnosis."}, {"id": "b", "text": "PAD is usually lower-extremity predominant in comparison table."}, {"id": "c", "text": "TAO affects only lower limbs in this note."}, {"id": "d", "text": "PAD primarily affects upper limbs in this note."}, {"id": "e", "text": "Upper and lower extremities can be affected."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Buerger disease may involve both upper and lower extremities, unlike PAD that mainly affects lower limbs.', 'Buerger''s Disease - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving BURGER mnemonic - burning pain, which statements are correct? (Select all that apply)', 'For management involving BURGER mnemonic - burning pain, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pain may occur at rest."}, {"id": "b", "text": "Burning pain is in mnemonic."}, {"id": "c", "text": "Pain appears only with exertion and never at rest in this note."}, {"id": "d", "text": "Pain is absent in TAO in this note."}, {"id": "e", "text": "Distal digits/feet are common sites."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Burning ischemic pain at rest in fingers/toes/feet is a key symptom.', 'Buerger''s Disease - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around BURGER mnemonic - ulcers. Which items should be included? (Select all that apply)', 'The nurse plans care around BURGER mnemonic - ulcers. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Ulcers are painful in TAO profile."}, {"id": "b", "text": "Distal ulceration suggests severe ischemia."}, {"id": "c", "text": "TAO ulcers are painless venous stasis ulcers in this note."}, {"id": "d", "text": "Ulceration never occurs in TAO in this note."}, {"id": "e", "text": "Digit ulcers are highlighted."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Painful ulceration of fingertips/toes is listed in BURGER mnemonic.', 'Buerger''s Disease - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support BURGER mnemonic - rubor? (Select all that apply)', 'During reassessment, which observations support BURGER mnemonic - rubor? (Select all that apply)', '[{"id": "a", "text": "Color is unaffected by position in this note."}, {"id": "b", "text": "Color changes are part of BURGER mnemonic."}, {"id": "c", "text": "Only fixed cyanosis with no variation occurs in this note."}, {"id": "d", "text": "Dependent rubor is listed."}, {"id": "e", "text": "Raynaud-like color changes are listed."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Dependent rubor/redness and Raynaud-like color changes are characteristic findings.', 'Buerger''s Disease - NCLEX', true, 84, 1, true);
