  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with BURGER mnemonic - gangrene in this note? (Select all that apply)', 'Which clues are consistent with BURGER mnemonic - gangrene in this note? (Select all that apply)', '[{"id": "a", "text": "Dry gangrene is advanced feature."}, {"id": "b", "text": "Only wet gangrene is described in this note."}, {"id": "c", "text": "Gangrene is never seen in TAO in this note."}, {"id": "d", "text": "Gangrene indicates severe progression."}, {"id": "e", "text": "Digits are common gangrene location."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Dry gangrene of digits may occur in advanced disease.', 'Buerger''s Disease - NCLEX', true, 85, 1, true);
