  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for BURGER mnemonic - extremity coolness. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for BURGER mnemonic - extremity coolness. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Extremities are warm and flushed in TAO in this note."}, {"id": "b", "text": "Temperature is unrelated to TAO in this note."}, {"id": "c", "text": "Distal extremities are emphasized."}, {"id": "d", "text": "Cool hands/feet are listed finding."}, {"id": "e", "text": "Temperature change reflects poor perfusion."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Extremities are often cool to touch, especially hands and feet.', 'Buerger''s Disease - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving BURGER mnemonic - reduced pulses, which statements are correct? (Select all that apply)', 'For management involving BURGER mnemonic - reduced pulses, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Reduced or absent pulses are listed."}, {"id": "b", "text": "Pulses remain strong in severe TAO in this note."}, {"id": "c", "text": "Pedal/radial pulses specifically mentioned."}, {"id": "d", "text": "Pulse loss indicates arterial compromise."}, {"id": "e", "text": "Pulse checks are unnecessary in TAO in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Distal pulses (pedal/radial) are reduced or absent.', 'Buerger''s Disease - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Additional signs. Which items should be included? (Select all that apply)', 'The nurse plans care around Additional signs. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Nail/neuropathy changes are listed."}, {"id": "b", "text": "Intermittent claudication is listed."}, {"id": "c", "text": "Only cardiac murmurs diagnose TAO in this note."}, {"id": "d", "text": "Neurologic changes are excluded in this note."}, {"id": "e", "text": "Migratory superficial thrombophlebitis is listed."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Additional signs include migratory superficial thrombophlebitis, intermittent claudication, nail changes, and ischemic neuropathy.', 'Buerger''s Disease - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Allen test purpose? (Select all that apply)', 'During reassessment, which observations support Allen test purpose? (Select all that apply)', '[{"id": "a", "text": "Allen test diagnoses DVT in this note."}, {"id": "b", "text": "Allen test evaluates hand arterial flow."}, {"id": "c", "text": "Both radial and ulnar arteries are assessed."}, {"id": "d", "text": "Allen test is unrelated to arterial patency in this note."}, {"id": "e", "text": "Used for upper-extremity circulation evaluation."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Allen test assesses radial/ulnar patency and upper-extremity circulation.', 'Buerger''s Disease - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Allen test steps in this note? (Select all that apply)', 'Which clues are consistent with Allen test steps in this note? (Select all that apply)', '[{"id": "a", "text": "Test begins with leg elevation in this note."}, {"id": "b", "text": "Hand should appear pale before release."}, {"id": "c", "text": "Release both arteries simultaneously is required in this note."}, {"id": "d", "text": "Release one artery while keeping the other compressed."}, {"id": "e", "text": "Both arteries are compressed initially."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Steps include fist clench, compress both radial/ulnar arteries, open blanched hand, release one artery, and observe reperfusion.', 'Buerger''s Disease - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Allen test interpretation. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Allen test interpretation. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Persistent pallor indicates occlusion."}, {"id": "b", "text": "Persistent pallor confirms normal flow in this note."}, {"id": "c", "text": "Any refill after 30 seconds is still normal in this note."}, {"id": "d", "text": "Flush in 5–7 seconds is normal."}, {"id": "e", "text": "Timing criterion is explicitly provided."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Normal test is flush within 5–7 seconds after release; persistent pallor suggests occlusion.', 'Buerger''s Disease - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Angiography hallmark, which statements are correct? (Select all that apply)', 'For management involving Angiography hallmark, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pattern supports TAO diagnosis."}, {"id": "b", "text": "Corkscrew collaterals are pathognomonic in note."}, {"id": "c", "text": "Corkscrew pattern indicates PAD only in this note."}, {"id": "d", "text": "Angiography is key diagnostic study."}, {"id": "e", "text": "Angiography is never used in TAO in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Angiography finding of corkscrew collaterals is pathognomonic for Buerger disease.', 'Buerger''s Disease - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Other diagnostics. Which items should be included? (Select all that apply)', 'The nurse plans care around Other diagnostics. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Doppler/ABI are listed supportive studies."}, {"id": "b", "text": "No reliable standalone biomarker is listed."}, {"id": "c", "text": "No imaging is required for diagnosis in this note."}, {"id": "d", "text": "Single specific blood biomarker confirms TAO in this note."}, {"id": "e", "text": "Blood tests help rule out other causes."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Doppler and ABI may be used; blood tests are used to rule out autoimmune/hypercoagulable causes, with no reliable biomarker.', 'Buerger''s Disease - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Primary treatment? (Select all that apply)', 'During reassessment, which observations support Primary treatment? (Select all that apply)', '[{"id": "a", "text": "Even low-level smoking can sustain disease activity."}, {"id": "b", "text": "Revascularization alone halts TAO despite smoking in this note."}, {"id": "c", "text": "Smoking reduction without cessation is sufficient in this note."}, {"id": "d", "text": "Progression continues with ongoing tobacco use."}, {"id": "e", "text": "Smoking cessation is mandatory and first priority."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Absolute cessation of all smoking/tobacco is the only intervention that halts progression.', 'Buerger''s Disease - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Nicotine product caution in this note? (Select all that apply)', 'Which clues are consistent with Nicotine product caution in this note? (Select all that apply)', '[{"id": "a", "text": "Any nicotine exposure is concerning in TAO."}, {"id": "b", "text": "Nicotine patches are guaranteed curative in TAO in this note."}, {"id": "c", "text": "Only cigarette smoke, not nicotine, matters in this note."}, {"id": "d", "text": "Nicotine replacement products may worsen TAO per note."}, {"id": "e", "text": "Counseling should include smokeless/nicotine products."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Nicotine patches/gums may worsen disease because nicotine exposure can maintain activity.', 'Buerger''s Disease - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Supportive therapy. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Supportive therapy. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Nifedipine for vasospasm is listed."}, {"id": "b", "text": "Wound care is listed supportive management."}, {"id": "c", "text": "Supportive care is unnecessary if ulcers present in this note."}, {"id": "d", "text": "Cold exposure is recommended in this note."}, {"id": "e", "text": "Avoiding cold triggers is listed advice."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Supportive management includes wound care, CCB for vasospasm, iloprost for severe ischemia, pain control, and avoiding cold.', 'Buerger''s Disease - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Amputation context, which statements are correct? (Select all that apply)', 'For management involving Amputation context, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Gangrene always reverses without intervention in this note."}, {"id": "b", "text": "Gangrene surveillance is key nursing focus."}, {"id": "c", "text": "Advanced ischemia may progress despite support."}, {"id": "d", "text": "Amputation is contraindicated in all cases in this note."}, {"id": "e", "text": "Non-viable gangrene can require amputation."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Amputation may be required when gangrene is non-viable.', 'Buerger''s Disease - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Buerger vs PAD cause/age. Which items should be included? (Select all that apply)', 'The nurse plans care around Buerger vs PAD cause/age. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Buerger age profile is younger than PAD in table."}, {"id": "b", "text": "Buerger is primarily elderly disease in this note."}, {"id": "c", "text": "Buerger cause is tobacco inflammation in table."}, {"id": "d", "text": "PAD cause is atherosclerosis in table."}, {"id": "e", "text": "Buerger and PAD share identical etiology in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Buerger is tobacco-induced in younger patients (<45), while PAD is atherosclerotic and generally older (>50).', 'Buerger''s Disease - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Buerger vs PAD vessel/risk patterns? (Select all that apply)', 'During reassessment, which observations support Buerger vs PAD vessel/risk patterns? (Select all that apply)', '[{"id": "a", "text": "Buerger affects only large proximal vessels in this note."}, {"id": "b", "text": "PAD risk factor is tobacco only in this note."}, {"id": "c", "text": "PAD mostly affects lower extremities."}, {"id": "d", "text": "Buerger can affect upper and lower extremities."}, {"id": "e", "text": "PAD risk list includes HTN/DM/lipids/smoking in table."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Buerger affects small/medium vessels in upper and lower limbs with tobacco-only risk; PAD affects large/medium mostly lower limbs with multiple metabolic risks.', 'Buerger''s Disease - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with NCLEX priority synthesis in this note? (Select all that apply)', 'Which clues are consistent with NCLEX priority synthesis in this note? (Select all that apply)', '[{"id": "a", "text": "Stop all tobacco is first intervention."}, {"id": "b", "text": "Young smoker + bilateral ischemia is key TAO clue."}, {"id": "c", "text": "Gangrene progression monitoring is emphasized."}, {"id": "d", "text": "Gangrene monitoring is low priority in this note."}, {"id": "e", "text": "Smoking cessation is optional in TAO in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: NCLEX priority: young male smoker with bilateral ischemia suggests Buerger; immediate STOP ALL TOBACCO and monitor gangrene progression.', 'Buerger''s Disease - NCLEX', true, 100, 1, true);
